class Admin_Model_ProductDocumment extends Admin_Model_Base_ProductDocumment {

    public function save(Doctrine_Connection $conn = null) {
        parent::save($conn);
//        Admin_Model_Product::updateProductDateTime($this->Product_ID);
    }

    /**
     * @param int $productID
     * @return array
     */
    public static function getProductDocumments(int $productID): array {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductDocumment object');
        $query->leftJoin('object.file file');
        $query->where('object.Product_ID = ?', $productID);

        return $query->execute()->toArray();
    }

    public static function getProductDocumentByProductAndFileID(int $productID, int $originalFileID) {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductDocumment object');
        $query->where('object.Product_ID = ?', $productID);
        $query->andWhere('object.File_ID = ?', $originalFileID);
        return $query->fetchOne();
    }

}